import { BiquadEffect, calcLowShelfCoeffs, calcPeakingCoeffs } from "./BiquadEffect.js";
import { userToGainDb } from "./utils.js";

export class BassEffect extends BiquadEffect {
  private _normalized: number;
  private _sampleRate: number;

  constructor(channels: number, sampleRate: number, normalized: number) {
    super(
      "bass",
      () => {
        const gainDb = userToGainDb(this._normalized, 18);
        const shelf = calcLowShelfCoeffs(120, this._sampleRate, gainDb, 0.7);
        let peak = null;
        if (Math.abs(gainDb) > 6) {
          peak = calcPeakingCoeffs(60, this._sampleRate, gainDb * 0.5, 1.0);
        }
        return { shelf, peak };
      },
      () => Math.abs(this._normalized) > 0.001,
      channels,
    );
    this._sampleRate = sampleRate;
    this._normalized = normalized;
  }

  get value(): number {
    return this._normalized;
  }

  setBass(v: number): void {
    this._normalized = v;
    this.invalidate();
  }
}
